jQuery(document).ready(function($){if($('body').hasClass('otpa-page')){$('link[rel="stylesheet"],style').each(function(index,el){var style=$(el);if(style.attr('id')&&style.attr('id').indexOf('otpa')===-1&&style.attr('id').indexOf('dashicons')===-1){style.remove();}});}var showOtpWrapper=function(){$('.otpa-wrapper').fadeIn();};var logoHolder=$('#otpa_logo'),logoUrl=logoHolder.length?logoHolder.data('otp_logo_url'):'';if(logoUrl){var logo=new Image();logo.src=logoUrl;$(logo).on('load',function(){logoHolder.css('background-image','url('+$(this).attr('src')+')');showOtpWrapper();}).on('error',showOtpWrapper);window.setTimeout(showOtpWrapper,3000);}else{showOtpWrapper();}window.requestOTPCodeEvent=new CustomEvent('requestOTPCode');window.requestOTPCode=function(){window.dispatchEvent(window.requestOTPCodeEvent);};window.addEventListener('requestOTPCode',function(){procesRequestOTPCode();});var procesRequestOTPCode=function(){var form=$('#otpa_otp_form'),data={nonce:form.find('#otpa_nonce').val(),handler:'request_otp_code',otpType:form.data('otp_form_type'),payload:{identifier:form.find('#otpa_id').val()}};form.find('#otpa_result').html('');$.post(OTPA.otpa_api_url,data,function(response){if(!response.success&&response.data&&response.data.message){form.find('#otpa_result').html(response.data.message);}else if(response.data&&response.data.message){form.find('#otpa_result').html(response.data.message);}else{form.find('#otpa_result').html(form.find('#otpa_unknown_result').html());}}).fail(function(){form.find('#otpa_result').html(form.find('#otpa_unknown_result').html());});},getUrlParameter=function getUrlParameter(param){var pageUrl=window.location.search.substring(1),urlVariables=pageUrl.split('&'),parameterName,i;for(i=0;i<urlVariables.length;i++){parameterName=urlVariables[i].split('=');if(parameterName[0]===param){return parameterName[1]===undefined?true:decodeURIComponent(parameterName[1]);}}},getRedirectTo=function getRedirectTo(form){var shortcodeRedirect=form.data('redirect_to');return shortcodeRedirect||getUrlParameter('redirect_to');};$('#otpa_id_widget').on('change',function(){$(this).closest('#otpa_otp_form').find('#otpa_id').val($(this).val());});$('#otpa_code_widget').on('keyup',function(){$(this).trigger('change');});$('#otpa_code_widget').on('change',function(){var code=$(this).val();var form=$(this).closest('#otpa_otp_form');form.find('#otpa_code').val(code);if(0<code.length){form.find('#otpa_submit').removeAttr('disabled');}else{form.find('#otpa_submit').attr('disabled','disabled');}});$('#otpa_set_id_input').on('keyup',function(){var form=$(this).closest('#otpa_otp_form'),input=$(this).val();form.find('#otpa_id').val($(this).val());if(0<input.length){form.find('#otpa_submit').removeAttr('disabled');}else{form.find('#otpa_submit').attr('disabled','disabled');}});$('#otpa_submit').on('click',function(e){e.preventDefault();var button=$(this),form=button.closest('#otpa_otp_form'),data={nonce:form.find('#otpa_nonce').val(),handler:form.data('handler'),otpType:form.data('otp_form_type'),payload:{code:form.find('#otpa_code').val(),identifier:form.find('#otpa_id').val(),redirect:getRedirectTo(form),}};form.find('#otpa_result').html('');form.find('input').attr('disabled','disabled');button.attr('disabled','disabled');$.post(OTPA.otpa_api_url,data,function(response){if(!response.success&&response.data&&response.data.message){form.find('#otpa_result').html(response.data.message);form.find('input').removeAttr('disabled');}else if(response.data&&response.data.message){form.find('#otpa_result').html(response.data.message);if(response.data.redirect){window.location.replace(response.data.redirect);}else{window.location.reload();}}else{form.find('#otpa_result').html(form.find('#otpa_unknown_result').html());form.find('input').removeAttr('disabled');button.removeAttr('disabled');}}).fail(function(){form.find('#otpa_result').html(form.find('#otpa_unknown_result').html());});});});